  ('heelevel3-6e2f88c7-moex-00180', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-112-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '依據實務見解，納稅義務人因違反稅法規定而受罰鍰處分，惟納稅義務人於行政訴訟程序中死亡， 則罰鍰處分應如何處置？', '["因納稅義務人死亡，法律關係即告消滅，故無法執行該罰鍰處分", "由繼承人繼承被繼承人之義務人地位，並繳納罰鍰", "納稅義務人死亡後，法院應以欠缺當事人能力為由駁回訴訟", "由繼承人於被繼承人遺產範圍內代繳罰鍰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:45+00:00", "source_pdf_sha1": "4bc34ba84b99", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
